```class Solution {
public:
    bool makeStringsEqual(string s, string target) {
        int onesInS = 0, onesInTarget = 0;
        for (char c : s) {
            onesInS += c - '0';
        }
        for (char c : target) {
            onesInTarget += c - '0';
        }
        return onesInS & 1 == onesInTarget & 1;
    }
};```
